+// AGGREGATE and EXTEND are only clauses in BigQuery pipe syntax.
+function promotePipeClauses(tokens: Token[]): Token[] {
+  return tokens.map((token, index) => {
+    const previous = tokens[index - 1];
+    if (
+      previous?.type === TokenType.PIPE &&
+      token.type === TokenType.IDENTIFIER &&
+      (token.text.toUpperCase() === 'AGGREGATE' || token.text.toUpperCase() === 'EXTEND')
+    ) {
+      return { ...token, type: TokenType.RESERVED_CLAUSE, text: token.text.toUpperCase() };
+    }
+    return token;
+  });
+}
